const data = $input.first().json;

// 1. Buscamos el texto de la IA en todo el objeto
function encontrarTexto(obj) {
    if (typeof obj === 'string' && obj.includes('[JSON AGENDA]')) return obj;
    if (obj && typeof obj === 'object') {
        for (let key in obj) {
            let result = encontrarTexto(obj[key]);
            if (result) return result;
        }
    }
    return "";
}

let textoGemini = encontrarTexto(data);
if (!textoGemini) {
    textoGemini = JSON.stringify(data); // Rescate de emergencia
}

let correo = "";
let agenda = [];

// 2. Método Infalible: Cortamos el texto por posición matemática (sin usar Split ni Arrays)
let puntoDeCorte = textoGemini.indexOf("[JSON AGENDA]");

if (puntoDeCorte !== -1) {
    // Tomamos todo lo que está ARRIBA del punto de corte
    let textoArriba = textoGemini.substring(0, puntoDeCorte);
    correo = textoArriba.replace("[RESUMEN Y FEEDBACK]", "").trim();

    // Tomamos todo lo que está ABAJO del punto de corte
    let rawAgenda = textoGemini.substring(puntoDeCorte + 13);

    // 3. AUTO-REPARACIÓN DEL JSON DE GEMINI
    let inicio = rawAgenda.indexOf("{");
    // Agregamos una doble validación por si Gemini manda el array con corchetes directamente
    if (rawAgenda.indexOf("[") !== -1 && rawAgenda.indexOf("[") < inicio) {
        inicio = rawAgenda.indexOf("[");
    }

    let fin = rawAgenda.lastIndexOf("}");
    if (rawAgenda.lastIndexOf("]") > fin) {
        fin = rawAgenda.lastIndexOf("]");
    }

    if (inicio !== -1 && fin !== -1) {
        let jsonStr = rawAgenda.substring(inicio, fin + 1);

        // Ponemos corchetes si Gemini los olvidó
        if (!jsonStr.startsWith("[")) {
            jsonStr = "[" + jsonStr + "]";
        }
        if (!jsonStr.endsWith("]")) {
            jsonStr = jsonStr + "]";
        }

        // Limpiamos comas basura
        jsonStr = jsonStr.replace(/,\s*\]/g, "]");

        try {
            agenda = JSON.parse(jsonStr);

            // --- MAGIA NUEVA: AGREGAMOS EL DETALLE DE LA AGENDA AL CORREO ---
            correo += "\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n";
            correo += "📋 DETALLE DE LA RUTINA SEMANAL:\n";
            correo += "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n";

            // Recorremos cada día de entrenamiento y lo sumamos al texto del correo
            agenda.forEach(dia => {
                correo += `📅 ${dia.dia} | 🏅 ${dia.deporte}\n`;
                correo += `⏰ ${dia.hora_inicio} (${dia.duracion_minutos} min)\n`;
                correo += `📝 ${dia.descripcion}\n\n`;
            });
            // ----------------------------------------------------------------

        } catch(e) {
            correo += "\n\n(Aviso: No se pudo formatear la agenda al calendario).";
        }
    }
} else {
    // Si no encuentra la etiqueta, manda todo al correo
    correo = textoGemini.replace("[RESUMEN Y FEEDBACK]", "").trim();
}

// 4. Salida final
return [{ 
    json: { 
        correo: correo, 
        agenda: agenda 
    } 
}];

for (const item of $input.all()) {
  // 1. Tomamos la hora de inicio y la duración en minutos
  let [hora, minuto] = item.json.hora_inicio.split(':').map(Number);
  let totalMinutos = (hora * 60) + minuto + item.json.duracion_minutos;

  // 2. Calculamos a qué hora exacta termina el entrenamiento
  let finHora = Math.floor(totalMinutos / 60);
  let finMinuto = totalMinutos % 60;

  // 3. Formateamos con ceros a la izquierda (ej. 06:05:00)
  let finHoraStr = String(finHora).padStart(2, '0');
  let finMinutoStr = String(finMinuto).padStart(2, '0');

  // 4. Creamos el formato estricto que exige Google Calendar
  item.json.start_datetime = `${item.json.dia}T${item.json.hora_inicio}:00`;
  item.json.end_datetime = `${item.json.dia}T${finHoraStr}:${finMinutoStr}:00`;

// 4. AQUÍ LA MAGIA: Formato estricto + Zona Horaria de Argentina (-03:00)
  item.json.start_datetime = `${item.json.dia}T${item.json.hora_inicio}:00-03:00`;
  item.json.end_datetime = `${item.json.dia}T${finHoraStr}:${finMinutoStr}:00-03:00`;

}

return $input.all();
